using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr docs = app->documents();
    if (!docs)
        return false;

    // Create a document.
    Ptr doc = docs->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr design = app->activeProduct();
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create a sketch that has a rectangle in it
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;

    Ptr sketch = sketches->add(rootComp->xZConstructionPlane());
    if (!sketch)
        return false;

    Ptr curves = sketch->sketchCurves();
    if (!curves)
        return false;

    Ptr sketchLines = curves->sketchLines();
    if (!sketchLines)
        return false;

    Ptr point0 = adsk::core::Point3D::create(0, 0, 0);
    if (!point0)
        return false;
    Ptr point1 = adsk::core::Point3D::create(10, 10, 0);
    if (!point1)
        return false;

    sketchLines->addTwoPointRectangle(point0, point1);

    // Get the profile defined by the circle
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;

    Ptr prof = profs->item(0);
    if (!prof)
        return false;

    // Create an extrusion input
    Ptr feats = rootComp->features();
    if (!feats)
        return false;

    Ptr extrudes = feats->extrudeFeatures();
    if (!extrudes)
        return false;

    Ptr extInput = extrudes->createInput(prof, FeatureOperations::NewBodyFeatureOperation);
    if (!extInput)
        return false;

    // Define that the extent is a distance extent of 5 cm
    Ptr distance = ValueInput::createByReal(5);
    if (!distance)
        return false;

    extInput->setDistanceExtent(true, distance);

    // Create the extrusion
    Ptr ext = extrudes->add(extInput);
    if (!ext)
        return false;

    // Get one edge of the extrusion body
    Ptr faces = ext->endFaces();
    if (!faces)
        return false;
    Ptr face = faces->item(0);
    if (!face)
        return false;
    Ptr edges = face->edges();
    if (!edges)
        return false;
    Ptr edge = edges->item(0);
    if (!edge)
        return false;

    // Create a slant construction plane with an angle of 45 deg on the xZConstructionPlane
    Ptr planes = rootComp->constructionPlanes();
    if (!planes)
        return false;

    Ptr planeInput = planes->createInput();
    if (!planeInput)
        return false;
    planeInput->setByAngle(edge, adsk::core::ValueInput::createByString("45 deg"), rootComp->xZConstructionPlane());
    Ptr plane = planes->add(planeInput);

    // Create another sketch containing a circle profile on the slant plane
    Ptr toolSketch = sketches->add(plane);
    if (!toolSketch)
        return false;
    Ptr toolCurves = toolSketch->sketchCurves();
    if (!toolCurves)
        return false;
    Ptr sketchCircles = toolCurves->sketchCircles();
    if (!sketchCircles)
        return false;
    Ptr circle = sketchCircles->addByCenterRadius(point0, 5.0);
    if (!circle)
        return false;

    // Get SplitFaceFetures
    Ptr splitFaceFeats = feats->splitFaceFeatures();
    if (!splitFaceFeats)
        return false;

    // Set faces to split
    Ptr facesCol = ObjectCollection::create();
    if (!facesCol)
        return false;
    facesCol->add(face);

    // Create Create a split face feature of surface intersection split type
    Ptr splitFaceInput = splitFaceFeats->createInput(facesCol, circle, true);
    if (!splitFaceInput)
        return false;
    Ptr split = splitFaceFeats->add(splitFaceInput);
    if (!split)
        return false;
    split->deleteMe();

    // Create another split face feature of closest point split type
    splitFaceInput->setClosestPointSplitType();
    split = splitFaceFeats->add(splitFaceInput);
    if (!split)
        return false;
    split->deleteMe();

    // Create another split face feature of along vector split type
    Ptr dirEdge = edges->item(1);
    if (!dirEdge)
        return false;
    splitFaceInput->setAlongVectorSplitType(dirEdge);
    splitFaceFeats->add(splitFaceInput);

    return true;
}
